import{_ as o,o as r,c as a,a3 as t}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"199. Hours Of Work","description":"","frontmatter":{"title":"199. Hours Of Work","eba":"Mental Health Services 2024-2028","topics":["leave","hours","shift-work"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/hours-of-work/199-hours-of-work.md","filePath":"ebas/mental-health/management-admin/hours-of-work/199-hours-of-work.md"}'),s={name:"ebas/mental-health/management-admin/hours-of-work/199-hours-of-work.md"};function n(h,e,i,l,d,f){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="_199-hours-of-work" tabindex="-1">199. Hours Of Work <a class="header-anchor" href="#_199-hours-of-work" aria-label="Permalink to &quot;199. Hours Of Work&quot;">​</a></h1><p><strong>199.1</strong> The ordinary hours of work for a full-time Employee shall be 38 hours, or an average of 38 hours, per week.</p><p><strong>199.2</strong> For the purposes of clause 199.1, the ordinary hours an Employee works in a week are taken to include any hours of authorised leave, or absence, whether paid or unpaid, that the Employee takes in a week.</p><p><strong>199.3</strong> The working week shall commence at midnight on a Sunday.</p><p><strong>199.4</strong> Notwithstanding any authorised meal breaks or rest breaks, the work of each day/shift shall be continuous.</p><p><strong>199.5</strong> Management and Administrative Officers For Employees classified under <a href="/eba/ebas/mental-health/schedules/07-management-and-administrative-officers-classifications.html">Schedule 7</a> of this Agreement the ordinary hours of work shall be worked either:</p><p><strong>(a)</strong> in 5 days of shifts of not more than 8 hours each; or</p><p><strong>(b)</strong> by mutual agreement:</p><p><strong>(i)</strong> in weeks of four days in shifts of not more than 10 hours each; or</p><p><strong>(ii)</strong> in some other averaging arrangement, provided that the length of any ordinary day does not exceed ten hours, and that not more than 50 ordinary hours is worked in any one week.</p>',10)])])}const p=o(s,[["render",n]]);export{m as __pageData,p as default};
